-- MOM VILLAGE — MIGRATION 13
-- Loads all 42 months of locked Monthly Chart content (pregnancy month -6
-- through age-3 month 36), and restructures the section categories to match
-- the content as actually written — 6 real categories instead of the original
-- placeholder Money / Development / Environment scaffold, which never matched
-- how the locked docx content was organized.

-- Widen section to the 6 real categories used by the locked content.
alter table monthly_chart_content drop constraint if exists monthly_chart_content_section_check;
alter table monthly_chart_content add constraint monthly_chart_content_section_check
  check (section in ('baby_development','mum_wellbeing','buy_now','hold_off','movement_rest','appointments_safety'));

-- Content items are single flowing sentences/paragraphs as authored, not a
-- short-title + elaboration pair, so title becomes optional.
alter table monthly_chart_content alter column title drop not null;

-- Clear any previous test/partial rows before loading the real locked content.
delete from monthly_chart_content;

