insert into monthly_chart_content (month_number, section, delivery_type, season, title, body, sort_order) values
(-6, 'baby_development', 'any', 'any', null, 'The anomaly scan (detailed ultrasound) is often scheduled around 18–22 weeks — checking baby''s anatomy, growth, placenta, and amniotic fluid. Follow your obstetrician''s timing.', 0),
(-6, 'baby_development', 'any', 'any', null, 'Many mums start feeling first flutters or movements around now, though first-time mums often notice this a little later than second-time mums.', 1),
(-6, 'mum_wellbeing', 'any', 'any', null, 'Your bump becomes more visible; some mums start needing maternity wear around now.', 0),
(-6, 'mum_wellbeing', 'any', 'any', null, 'Second-trimester energy often returns, and appetite may increase.', 1),
(-6, 'mum_wellbeing', 'any', 'any', null, 'Skin changes like a dark line down the belly (linea nigra) or slight darkening of skin can appear — common, and usually fades after delivery.', 2),
(-6, 'mum_wellbeing', 'any', 'any', null, 'At your visit, discuss hydration, constipation, appetite changes, and nourishing iron- and protein-rich foods if these are concerns.', 3),
(-6, 'buy_now', 'any', 'any', null, 'A few comfortable maternity wear basics — no need to over-buy, just what feels good right now.', 0),
(-6, 'buy_now', 'any', 'any', null, 'Start a simple pregnancy folder: scan reports, blood tests, doctor''s notes, all in one place.', 1),
(-6, 'buy_now', 'any', 'any', null, 'If you like planning early, casually start noting pediatrician/hospital names — no decisions needed yet.', 2),
(-6, 'hold_off', 'any', 'any', null, 'Big-ticket nursery furniture (crib, stroller) — a couple more months gives you better research and post-scan clarity.', 0),
(-6, 'hold_off', 'any', 'any', null, 'Nursery painting or renovation involving strong fumes — hold off, or ensure real ventilation and don''t do it yourself.', 1),
(-6, 'movement_rest', 'any', 'any', null, 'If your doctor has cleared it: walking, prenatal yoga, or swimming in a clean, safe setting — this trimester is often a comfortable window for movement.', 0),
(-6, 'movement_rest', 'any', 'any', null, 'Stop exercising and contact your doctor for bleeding, fluid leakage, chest pain, faintness/dizziness, painful regular contractions, or calf pain/swelling.', 1),
(-6, 'movement_rest', 'any', 'any', null, 'Round ligament pain (mild stretching on either side of the belly) is common — but mention anything severe to your doctor.', 2),
(-6, 'movement_rest', 'any', 'any', null, 'Left-side sleeping often starts becoming more comfortable and is generally recommended around now.', 3),
(-6, 'appointments_safety', 'any', 'any', null, 'Attend the anomaly scan if it is scheduled this month, and ask your doctor to explain anything you do not fully understand.', 0),
(-6, 'appointments_safety', 'any', 'any', null, 'At each antenatal visit, ask whether blood pressure, weight, urine testing, haemoglobin/anaemia follow-up, and prescribed supplements or vaccinations are due.', 1),
(-6, 'appointments_safety', 'any', 'any', null, 'Bring your MCP card or pregnancy records; if using public services, ask your ASHA/ANM about local ANC and PMSMA services.', 2),
(-6, 'appointments_safety', 'any', 'any', null, 'Discuss any travel plans with your doctor if you''re considering travel during this window.', 3),
(-6, 'appointments_safety', 'any', 'any', null, 'Contact your doctor promptly for vaginal bleeding, fluid leakage, severe abdominal pain or cramping, high fever, severe headache, vision changes, sudden swelling, or a worrying change in movements.', 4),
(-6, 'appointments_safety', 'any', 'winter', null, 'Layer clothing rather than one heavy layer — easier to adjust as you move between indoors and out.', 5),
(-6, 'appointments_safety', 'any', 'winter', null, 'Ask your doctor about flu vaccination timing if it hasn''t come up yet.', 6),
(-6, 'appointments_safety', 'any', 'winter', null, 'Keep skin moisturized as weather turns dry, especially over the growing belly.', 7),
(-5, 'baby_development', 'any', 'any', null, 'Baby may now respond to familiar voices and sounds.', 0),
(-5, 'baby_development', 'any', 'any', null, 'Movements often become more noticeable and predictable, though every pregnancy is different.', 1),
(-5, 'baby_development', 'any', 'any', null, 'Ask whether glucose screening is due later this month or next month; it is commonly done around 24–28 weeks, depending on your exact pregnancy week and medical history.', 2),
(-5, 'mum_wellbeing', 'any', 'any', null, 'You may feel more energetic, but backache, heartburn, leg cramps, and sleep changes can begin.', 0),
(-5, 'mum_wellbeing', 'any', 'any', null, 'Notice your baby''s usual movement pattern, without turning it into a stressful daily count yet; ask your doctor when they want you to start formal movement monitoring.', 1),
(-5, 'mum_wellbeing', 'any', 'any', null, 'Take only the iron, folic acid, calcium, and other medicines prescribed by your obstetrician.', 2),
(-5, 'mum_wellbeing', 'any', 'any', null, 'Choose one person who can accompany you to appointments or step in when you need practical help and rest.', 3),
(-5, 'buy_now', 'any', 'any', null, 'Shortlist a paediatrician and delivery hospital; ask about emergency access, NICU availability if relevant, breastfeeding support, room options, and costs.', 0),
(-5, 'buy_now', 'any', 'any', null, 'Review maternity insurance, cashless-hospital rules, waiting periods, and documents needed for claims.', 1),
(-5, 'buy_now', 'any', 'any', null, 'Create a simple baby budget: delivery, postpartum recovery, essentials, and a small contingency fund.', 2),
(-5, 'buy_now', 'any', 'any', null, 'If working, quietly review maternity-leave policy and handover planning.', 3),
(-5, 'hold_off', 'any', 'any', null, 'Bulk diapers, wipes, bottles, formula, or newborn clothes.', 0),
(-5, 'hold_off', 'any', 'any', null, 'Nursery decor and storage products bought only for appearance.', 1),
(-5, 'hold_off', 'any', 'any', null, 'Finalising a stroller, crib, or car seat just because there''s a sale — compare first, then buy closer to Month -4/-3.', 2),
(-5, 'hold_off', 'any', 'any', null, 'Large stockpiles of any feeding item before baby''s needs are known.', 3),
(-5, 'movement_rest', 'any', 'any', null, 'If your doctor has cleared activity: comfortable walking, gentle prenatal mobility, stretching, and pelvic-floor relaxation/awareness.', 0),
(-5, 'movement_rest', 'any', 'any', null, 'Stop exercising and contact your doctor for bleeding, fluid leakage, chest pain, faintness/dizziness, painful regular contractions, or calf pain/swelling.', 1),
(-5, 'movement_rest', 'any', 'any', null, 'Choose low-impact movement; avoid overheating, dehydration, falls, and exercise that causes pain or dizziness.', 2),
(-5, 'movement_rest', 'any', 'any', null, 'Make rest easier: supportive pillows, comfortable footwear, regular hydration, and brief movement breaks if sitting for long periods.', 3),
(-5, 'appointments_safety', 'any', 'any', null, 'Attend scheduled antenatal checks and ask which tests are due based on your exact pregnancy week, including whether glucose screening is planned.', 0),
(-5, 'appointments_safety', 'any', 'any', null, 'Keep your MCP card or pregnancy records, insurance details, blood group, doctor''s contact, and one emergency contact together.', 1),
(-5, 'appointments_safety', 'any', 'any', null, 'At each visit, ask whether blood pressure, urine testing, haemoglobin/anaemia follow-up, and prescribed supplements or vaccinations are due.', 2),
(-5, 'appointments_safety', 'any', 'any', null, 'Discuss flu vaccination and any locally recommended vaccines with your obstetrician.', 3),
(-5, 'appointments_safety', 'any', 'any', null, 'Contact your maternity team promptly for vaginal bleeding, fluid leakage, severe headache, vision changes, sudden swelling, severe abdominal pain, fever, or a concerning change in movements.', 4),
(-5, 'appointments_safety', 'any', 'winter', null, 'Ask about flu protection early.', 5),
(-5, 'appointments_safety', 'any', 'winter', null, 'Use gentle warmth and movement for back/joint stiffness.', 6),
(-5, 'appointments_safety', 'any', 'winter', null, 'Moisturise dry, stretching skin; choose fragrance-free products if your skin is sensitive.', 7),
(-4, 'baby_development', 'any', 'any', null, 'Baby''s movements often become stronger and more coordinated — you may start noticing patterns, like more activity at certain times of day.', 0),
(-4, 'baby_development', 'any', 'any', null, 'Baby is gaining weight, while the lungs and other organs continue maturing for life after birth.', 1),
(-4, 'baby_development', 'any', 'any', null, 'Baby can often respond with movement to familiar voices or sudden loud sounds at this stage.', 2),
(-4, 'mum_wellbeing', 'any', 'any', null, 'Some mums begin noticing Braxton Hicks (practice tightenings) — they are usually mild, irregular, and settle with rest or hydration. Call your doctor if they become painful, regular, or increase.', 0),
(-4, 'mum_wellbeing', 'any', 'any', null, 'Backaches and evening swelling in feet/ankles can become more noticeable as weight increases.', 1),
(-4, 'mum_wellbeing', 'any', 'any', null, 'Frequent urination may increase as the uterus grows and presses on the bladder; burning or pain while passing urine should be discussed with your doctor.', 2),
(-4, 'mum_wellbeing', 'any', 'any', null, 'Continue your prescribed supplements, and mention any unusual swelling, headaches, or vision changes to your doctor promptly.', 3),
(-4, 'buy_now', 'any', 'any', null, 'If you have been researching the crib, car seat, and stroller, this is a good window to start finalising. For a car seat, check that it is rear-facing for a newborn and fits your vehicle before buying.', 0),
(-4, 'buy_now', 'any', 'any', null, 'A baby monitor is optional. If you are considering one, compare features and cost, but do not rely on it to monitor breathing or replace safe-sleep practices.', 1),
(-4, 'buy_now', 'any', 'any', null, 'Begin a simple running hospital-bag list — full packing comes later, this is just for gathering thoughts.', 2),
(-4, 'hold_off', 'any', 'any', null, 'Newborn-size clothing in bulk — hold off until closer to delivery, since babies vary in size at birth.', 0),
(-4, 'hold_off', 'any', 'any', null, 'Elaborate nursery décor — functional basics matter more right now than aesthetics.', 1),
(-4, 'hold_off', 'any', 'any', null, 'Signing up for paid early-parenting classes before checking what your hospital or pediatrician already offers free.', 2),
(-4, 'movement_rest', 'any', 'any', null, 'If your doctor has cleared it: continue walking, prenatal yoga, or swimming in a clean, safe setting — watch for increased fatigue and adjust your pace as needed.', 0),
(-4, 'movement_rest', 'any', 'any', null, 'Stop exercising and contact your doctor for bleeding, fluid leakage, chest pain, faintness/dizziness, painful regular contractions, or calf pain/swelling.', 1),
(-4, 'movement_rest', 'any', 'any', null, 'Elevate your feet when resting to help with swelling; avoid standing for very long stretches.', 2),
(-4, 'movement_rest', 'any', 'any', null, 'Notice your posture as your centre of gravity shifts — this is a common source of new backache.', 3),
(-4, 'appointments_safety', 'any', 'any', null, 'Glucose screening is commonly done around 24–28 weeks. If it is due, attend it and discuss the result and next steps with your doctor.', 0),
(-4, 'appointments_safety', 'any', 'any', null, 'Confirm your antenatal check-up schedule going forward; visits may become more frequent as you approach or enter the third trimester.', 1),
(-4, 'appointments_safety', 'any', 'any', null, 'At each visit, ask whether blood pressure, weight, urine testing, haemoglobin/anaemia follow-up, fundal-height measurement, and prescribed supplements or vaccinations are due.', 2),
(-4, 'appointments_safety', 'any', 'any', null, 'If you are Rh-negative, ask your doctor whether Anti-D immunoglobulin is recommended around 28 weeks for your individual pregnancy.', 3),
(-4, 'appointments_safety', 'any', 'any', null, 'Keep your MCP card/records updated; if using public services, ask your ASHA/ANM about the local ANC schedule.', 4),
(-4, 'appointments_safety', 'any', 'any', null, 'Contact your doctor promptly for a worrying change, reduction, or stopping of movements; vaginal bleeding; fluid leakage; persistent headache; vision changes; sudden facial/hand swelling; severe abdominal pain; or fever.', 5),
(-4, 'appointments_safety', 'any', 'summer', null, 'Stay well hydrated — heat increases both swelling and dehydration risk during pregnancy.', 6),
(-4, 'appointments_safety', 'any', 'summer', null, 'Wear loose, breathable, light-coloured cotton clothing.', 7),
(-4, 'appointments_safety', 'any', 'summer', null, 'Avoid outdoor activity during peak heat; plan errands for cooler parts of the day.', 8),
(-4, 'appointments_safety', 'any', 'summer', null, 'Watch for signs of heat exhaustion (dizziness, excessive thirst, reduced urination) and contact your doctor if these occur.', 9),
(-3, 'baby_development', 'any', 'any', null, 'Baby''s brain, lungs, and other organs continue rapid development. Growth in the womb remains very important throughout the third trimester.', 0),
(-3, 'baby_development', 'any', 'any', null, 'Baby may settle into a more regular pattern of waking and sleeping that you can start to notice.', 1),
(-3, 'baby_development', 'any', 'any', null, 'Ask your doctor which movement-monitoring method they recommend and when to begin.', 2),
(-3, 'mum_wellbeing', 'any', 'any', null, 'Backaches, rib discomfort, and shortness of breath can increase as baby grows and space becomes tighter.', 0),
(-3, 'mum_wellbeing', 'any', 'any', null, 'Colostrum (early breast milk) may start leaking for some mums — this is normal, not a sign of anything wrong.', 1),
(-3, 'mum_wellbeing', 'any', 'any', null, 'Continue prescribed supplements; ask your doctor about iron levels if you''ve been feeling unusually tired.', 2),
(-3, 'mum_wellbeing', 'any', 'any', null, 'If sleep is difficult, ask your doctor about safe, pregnancy-appropriate options rather than any over-the-counter remedy on your own.', 3),
(-3, 'buy_now', 'any', 'any', null, 'Begin actually packing your hospital bag — for you, baby, and your birth partner, including ID/insurance documents and a phone charger.', 0),
(-3, 'buy_now', 'any', 'any', null, 'Postpartum recovery items: mesh underwear, maternity pads, nursing bras, nipple cream.', 1),
(-3, 'buy_now', 'any', 'any', null, 'Discuss your birth plan preferences with your doctor — pain-relief options, who you want present, and any specific wishes.', 2),
