(-1, 'buy_now', 'any', 'any', null, 'Confirm your support person''s availability and transport plan for the actual day, not just in general terms.', 2),
(-1, 'hold_off', 'any', 'any', null, 'Any new purchases beyond what''s already arranged — nothing new needs deciding this month.', 0),
(-1, 'hold_off', 'any', 'any', null, 'Nonessential long-distance travel; follow your doctor''s advice and any transport-provider rules.', 1),
(-1, 'hold_off', 'any', 'any', null, 'Overthinking a "perfect" birth plan — flexibility matters more now than a fixed script.', 2),
(-1, 'movement_rest', 'any', 'any', null, 'Gentle walking, if comfortable, may help you feel more at ease — but there''s no need to try to "exercise into labor."', 0),
(-1, 'movement_rest', 'any', 'any', null, 'Do not try castor oil, herbal remedies, nipple stimulation, or other methods to start labour unless your obstetrician specifically advises them.', 1),
(-1, 'movement_rest', 'any', 'any', null, 'Prioritise rest, while continuing gentle movement if comfortable and medically cleared.', 2),
(-1, 'movement_rest', 'any', 'any', null, 'Stop any activity and contact your doctor for bleeding, fluid leakage, chest pain, faintness/dizziness, painful regular contractions, or calf pain/swelling.', 3),
(-1, 'appointments_safety', 'any', 'any', null, 'Weekly antenatal visits are now common — confirm your doctor''s exact schedule.', 0),
(-1, 'appointments_safety', 'any', 'any', null, 'Ask whether GBS screening is due or has been completed; it is generally offered around 35–37 weeks.', 1),
(-1, 'appointments_safety', 'any', 'any', null, 'Ask your doctor to clearly explain the difference between Braxton Hicks and real labor contractions, so you know when to actually head in.', 2),
(-1, 'appointments_safety', 'any', 'any', null, 'If an induction or planned C-section is possible or scheduled, confirm the date, arrival time, fasting instructions, companion policy, and documents.', 3),
